	]
	return (
		<section>
			<Box sx={{display: 'flex', flexWrap: 'wrap', justifyContent: 'space-around', maxWidth: 1200, width: '90%', marginInline: 'auto'}}>
				{pagesData.slice(0, 3).map((page) => <CardWrapper {...page} />)}
			</Box>

		</section>
	)
}
